"use client";

import { useState } from "react";
import { searchDrugs, syncDrugs } from "@/util/drugApi"; // 위에서 만든 파일 import

export default function DrugPage() {
  const [keyword, setKeyword] = useState("");
  const [drugs, setDrugs] = useState<any[]>([]); // 약품 리스트
  const [loading, setLoading] = useState(false); // 로딩 상태
  const [message, setMessage] = useState(""); // 알림 메시지

  // 🔍 검색 핸들러
  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!keyword) return;

    setLoading(true);
    setMessage("검색 중입니다...");
    try {
      const data = await searchDrugs(keyword);
      setDrugs(data);
      setMessage(`총 ${data.length}개의 약품을 찾았습니다.`);
    } catch (err) {
      setMessage("검색 중 오류가 발생했습니다.");
    } finally {
      setLoading(false);
    }
  };

  // 🔄 전체 동기화 핸들러 (핵심 기능!)
  const handleSync = async () => {
    if (!confirm("모든 e약은요 데이터를 동기화하시겠습니까? (시간이 소요됩니다)")) return;

    setLoading(true);
    setMessage("데이터 동기화 중... 잠시만 기다려주세요.");
    try {
      const resultMsg = await syncDrugs();
      setMessage("✅ " + resultMsg);
      // 동기화 후 '타이레놀' 같은 예시로 자동 검색 한번 해주면 좋음
      // handleSearchAuto("타이레놀"); 
    } catch (err) {
      setMessage("❌ 동기화 실패! 백엔드 로그를 확인해주세요.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-8 max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold mb-6 text-gray-800">💊 e약은요 관리자 페이지</h1>

      {/* 상단 컨트롤 패널 */}
      <div className="flex flex-col md:flex-row gap-4 mb-8 bg-gray-100 p-6 rounded-xl">
        {/* 검색 폼 */}
        <form onSubmit={handleSearch} className="flex-1 flex gap-2">
          <input
            type="text"
            placeholder="약 이름 검색 (예: 타이레놀)"
            className="flex-1 p-3 border rounded-lg shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={keyword}
            onChange={(e) => setKeyword(e.target.value)}
          />
          <button
            type="submit"
            disabled={loading}
            className="bg-blue-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-blue-700 transition disabled:bg-gray-400"
          >
            검색
          </button>
        </form>

        {/* 동기화 버튼 (우측 배치) */}
        <button
          onClick={handleSync}
          disabled={loading}
          className="bg-green-600 text-white px-6 py-3 rounded-lg font-bold hover:bg-green-700 transition shadow-md disabled:bg-gray-400 whitespace-nowrap"
        >
          {loading ? "작업 중..." : "🔄 전체 데이터 동기화"}
        </button>
      </div>

      {/* 상태 메시지 */}
      {message && (
        <div className={`p-4 mb-6 rounded-lg text-center font-medium ${message.includes("❌") ? "bg-red-100 text-red-700" : "bg-blue-50 text-blue-700"}`}>
          {message}
        </div>
      )}

      {/* 로딩 스피너 */}
      {loading && (
        <div className="flex justify-center my-10">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
      )}

      {/* 결과 리스트 (카드 그리드 형태) */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {drugs.map((drug) => (
          <div key={drug.itemSeq} className="border rounded-xl p-5 shadow-sm hover:shadow-md transition bg-white flex flex-col">
            <div className="flex justify-between items-start mb-3">
              <h3 className="text-xl font-bold text-gray-900">{drug.itemName}</h3>
              <span className="text-xs bg-gray-200 text-gray-600 px-2 py-1 rounded">
                No. {drug.itemSeq}
              </span>
            </div>
            
            <p className="text-sm text-gray-500 mb-2">{drug.entpName}</p>
            
            {/* 이미지 (있으면 표시) */}
            {drug.itemImage && (
              <img src={drug.itemImage} alt={drug.itemName} className="w-full h-40 object-cover rounded-lg mb-3 border" />
            )}

            <div className="mt-auto">
              <p className="text-sm text-gray-700 line-clamp-3 bg-gray-50 p-3 rounded">
                <strong>효능:</strong> {drug.efficacy}
              </p>
            </div>
          </div>
        ))}
      </div>
      
      {drugs.length === 0 && !loading && (
        <div className="text-center text-gray-400 py-20">
          데이터가 없습니다. 검색하거나 동기화를 진행해주세요.
        </div>
      )}
    </div>
  );
}